from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an astronaut (or related entities) into a
    single fluent sentence. Handles a variety of predicates with simple
    templates and falls back to a generic “subject predicate object” format.
    """
    if not triples:
        return ""

    parts: list[str] = []
    for t in triples:
        subj, pred, obj = t.subject, t.predicate, t.object

        # Specific natural‑language templates for known predicates
        if pred == "birthDate":
            parts.append(f"{subj} was born on {obj}")
        elif pred == "birthPlace":
            parts.append(f"{subj} was born in {obj}")
        elif pred == "nationality":
            parts.append(f"{subj} was a citizen of {obj}")
        elif pred == "occupation":
            parts.append(f"{subj} worked as a {obj}")
        elif pred == "mission":
            parts.append(f"{subj} flew on the {obj} mission")
        elif pred == "dateOfRetirement":
            parts.append(f"{subj} retired in {obj}")
        elif pred == "status":
            parts.append(f"{subj} is {obj}")
        elif pred == "timeInSpace":
            parts.append(f"{subj} spent {obj} minutes in space")
        elif pred == "selectedByNasa":
            parts.append(f"{subj} was selected by NASA in {obj}")
        elif pred == "deathDate":
            parts.append(f"{subj} died on {obj}")
        elif pred == "deathPlace":
            parts.append(f"{subj} died in {obj}")
        elif pred == "title":
            parts.append(f"{subj} held the title of {obj}")
        elif pred == "award":
            parts.append(f"{subj} received the {obj}")
        elif pred == "ribbonAward":
            parts.append(f"{subj} received the {obj} ribbon")
        elif pred == "alternativeName":
            parts.append(f"{subj} is also known as {obj}")
        elif pred == "awards":
            parts.append(f"{subj} received {obj} awards")
        else:
            # Generic fallback
            parts.append(f"{subj} {pred} {obj}")

    # Join all parts into one coherent sentence
    sentence = "; ".join(parts) + "."
    return sentence

# EVOLVE-BLOCK-END

